sys_ws_operation.operation_script:
(function process(request, response) {
      var token = request.queryParams.token;
      if (Array.isArray(token)) token = token[0];

      response.setContentType('text/html');

      if (!token) {
          return _html(response, 400, 'Token ausente', 'Link invalido (sem token).');
      }

      var mlt = new x_1880990_chain.MagicLinkToken();
      var v = mlt.verify(token);
      if (!v.valid) {
          return _html(response, 401, 'Link invalido', 'Token invalido ou expirado.');
      }

      if (v.payload.a !== 'counter') {
          return _html(response, 400, 'Acao invalida', 'Token nao corresponde a contraproposta.');
      }

      var counterValue = _parseCounterValue(request);
      if (!counterValue || counterValue <= 0) {
          return _html(response, 400, 'Valor invalido', 'Informe um valor de contraproposta positivo.');
      }

      var p = new GlideRecord('x_1880990_chain_proposal');
      if (!p.get(v.payload.p)) {
          return _html(response, 404, 'Proposta nao encontrada', 'A proposta deste link nao existe mais.');
      }

      if (p.state.toString() !== '20') {
          return _html(response, 409, 'Estado invalido',
              'A proposta nao esta mais aguardando sua decisao (estado atual: ' + p.state.toString() + ').');
      }

      if (p.owner.toString() !== v.payload.o) {
          return _html(response, 403, 'Permissao negada', 'Voce nao e o proprietario desta proposta.');
      }

      p.counter_offer = counterValue;
      p.state = 30;
      p.work_notes = 'Contraproposta enviada via magic link: R$ ' + counterValue;
      p.update();

      return _html(response, 200, 'Contraproposta enviada',
          'Sua contraproposta de R$ ' + counterValue + ' foi enviada para ' + p.buyer.getDisplayValue() +
          '. O comprador sera notificado e pode aceitar, rejeitar ou enviar nova oferta. Voce pode fechar esta janela.');

      function _parseCounterValue(request) {
          try {
              var contentType = (request.getHeader('Content-Type') || '').toLowerCase();
              if (contentType.indexOf('application/x-www-form-urlencoded') >= 0) {
                  var raw = request.body.dataString || '';
                  var pairs = raw.split('&');
                  for (var i = 0; i < pairs.length; i++) {
                      var kv = pairs[i].split('=');
                      if (kv[0] === 'counter_offer') {
                          return parseFloat(decodeURIComponent(kv[1].replace(/\+/g, ' ')));
                      }
                  }   
              } else {
                  var data = request.body.data;
                  if (data && data.counter_offer) return parseFloat(data.counter_offer);
              }
          } catch (e) {
              gs.error('[counter_submit] parse error: ' + e.message);
          }
          return null;
      }

      function _html(response, status, title, message) {
          response.setStatus(status);
          var color = status === 200 ? '#27ae60' : '#c0392b';
          var body =
              '<html><head><meta charset="utf-8"><title>' + title + '</title></head>' +
              '<body style="font-family: Arial, sans-serif; max-width: 600px; margin: 80px auto; text-align: center;">' +
              '<h1 style="color: ' + color + ';">' + title + '</h1>' +
              '<p style="font-size: 1.1em; color: #333;">' + message + '</p>' +
              '<p style="color: #888; font-size: 12px; margin-top: 32px;">Chain Academy &mdash; Detran SP</p>' +
              '</body></html>';
          response.getStreamWriter().writeString(body);
      }
  })(request, response);
